import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.eQLvDOR_.js";const d=JSON.parse('{"title":"agent-computer-interface","description":"","frontmatter":{"title":"agent-computer-interface","concept":"Agent-Computer Interface","concept_id":"agent-computer-interface","aliases":["ACI","Tool-Prompting","工具提示工程"],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] Building Effective AI Agents.md"],"related_concepts":["[[augmented-llm]]"],"created_at":"2026-04-07","last_compiled":"2026-04-07"},"headers":[],"relativePath":"wiki/concepts/agent-computer-interface.md","filePath":"wiki/concepts/agent-computer-interface.md","lastUpdated":null}'),i={name:"wiki/concepts/agent-computer-interface.md"};function n(l,e,c,s,u,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="agent-computer-interface-aci" tabindex="-1">Agent-Computer Interface (ACI) <a class="header-anchor" href="#agent-computer-interface-aci" aria-label="Permalink to &quot;Agent-Computer Interface (ACI)&quot;">​</a></h1><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>正如人机交互 (HCI) 决定了人类使用软件的体验，<strong>Agent-Computer Interface (ACI)</strong> 决定了 AI 代理使用工具的成功率。</p><h2 id="aci-设计四原则" tabindex="-1">ACI 设计四原则 <a class="header-anchor" href="#aci-设计四原则" aria-label="Permalink to &quot;ACI 设计四原则&quot;">​</a></h2><ol><li><strong>给模型思考空间 (Tokens to Think)</strong>：在执行工具前允许模型生成思维链（思索）。</li><li><strong>贴近自然格式</strong>：保持工具输出格式接近互联网上自然出现的文本（例如 Markdown 而非过度转义的 JSON）。</li><li><strong>消除零散开销</strong>：避免让模型处理复杂的格式（如手动计算行数偏移或转义引号）。</li><li><strong>防呆设计 (Poka-yoke)</strong>：通过参数限制，让错误的调用方式难以发生。</li></ol><h2 id="工具-prompt-工程最佳实践" tabindex="-1">工具 Prompt 工程最佳实践 <a class="header-anchor" href="#工具-prompt-工程最佳实践" aria-label="Permalink to &quot;工具 Prompt 工程最佳实践&quot;">​</a></h2><ul><li><strong>清晰的参数名</strong>：像为同事编写文档注释一样编写工具说明。</li><li><strong>示例驱动</strong>：在定义中包含边界案例和输入要求。</li><li><strong>绝对路径优先</strong>：Agent 在移动目录后容易在相对路径上出错，强制使用绝对路径可显著提高稳定性。</li><li><strong>工作坊验证</strong>：在 Workbench 中模拟各种错误输入，观察模型如何误用工具并迭代。</li></ul><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><ul><li><strong>工具定义检查清单</strong>： <ul><li>[ ] 是否提供了 3 个以上的正向调用示例？</li><li>[ ] 是否在参数描述中明确了“单位”（如毫秒、相对路径）？</li><li>[ ] 是否包含错误处理分支（如果...则返回 XYZ 错误）？</li></ul></li><li><strong>Model-as-the-User 测试</strong>：在发布工具前，让另一个模型（如 GPT-4）模拟使用该 ACI，检查它是否能在不看外部文档的情况下正确调用。</li></ul><hr><h2 id="关键引用" tabindex="-1">关键引用 <a class="header-anchor" href="#关键引用" aria-label="Permalink to &quot;关键引用&quot;">​</a></h2><blockquote><p>&quot;Putting yourself in the model&#39;s shoes. Is it obvious how to use this tool, or would you need to think carefully about it?&quot;</p></blockquote><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Building Effective AI Agents.html">[Agent_Architecture] Building Effective AI Agents</a></li></ul>',16)])])}const p=t(i,[["render",n]]);export{d as __pageData,p as default};
